import{_ as t}from"./chunks/home-dashboard.BjFBEKEr.js";import{_ as o,o as a,c as s,ag as n}from"./chunks/framework.C9sp7nFj.js";const u=JSON.parse('{"title":"Attendance mode — for HR admins","description":"","frontmatter":{},"headers":[],"relativePath":"guide/attendance-mode.md","filePath":"guide/attendance-mode.md","lastUpdated":1776880543000}'),r={name:"guide/attendance-mode.md"};function i(h,e,d,c,l,p){return a(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="attendance-mode-—-for-hr-admins" tabindex="-1">Attendance mode — for HR admins <a class="header-anchor" href="#attendance-mode-—-for-hr-admins" aria-label="Permalink to &quot;Attendance mode — for HR admins&quot;">​</a></h1><p>Fateh HR lets your HR team pick how attendance is captured: the big <strong>Check In / Check Out</strong> button, or starting and stopping a <strong>task timer</strong>. Payroll runs off whichever one you choose.</p><p>This page is written for HR / admins. Employees don&#39;t see the toggle — they just see the flow you&#39;ve selected.</p><h2 id="where-to-set-it" tabindex="-1">Where to set it <a class="header-anchor" href="#where-to-set-it" aria-label="Permalink to &quot;Where to set it&quot;">​</a></h2><p>From the Frappe Desk:</p><ol><li>Go to <strong>Fateh HR Settings</strong> (search bar → type <code>Fateh HR Settings</code>).</li><li>Pick <strong>Attendance Mode</strong>: <ul><li><strong>Checkin Based</strong> — default</li><li><strong>Timer Based</strong></li></ul></li><li>Save. The next time an employee opens the app it picks up the new mode.</li></ol><div class="tip custom-block"><p class="custom-block-title">Offline awareness</p><p>Mobile apps cache the mode in their local storage. An employee who is offline when you flip the setting will keep using the old mode until their app syncs. Plan rollouts accordingly.</p></div><h2 id="mode-1-—-checkin-based-default" tabindex="-1">Mode 1 — Checkin Based (default) <a class="header-anchor" href="#mode-1-—-checkin-based-default" aria-label="Permalink to &quot;Mode 1 — Checkin Based (default)&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">When to pick this</p><p>You treat attendance as &quot;did the employee show up?&quot;. Task time tracking is a separate, optional thing for billable-hours / project costing.</p></div><table tabindex="0"><thead><tr><th>Action</th><th>What happens</th></tr></thead><tbody><tr><td>Employee taps <strong>Check In</strong></td><td>GPS + optional selfie captured. Creates <strong>Employee Checkin (IN)</strong>.</td></tr><tr><td>Employee taps <strong>Check Out</strong></td><td>GPS captured. Creates <strong>Employee Checkin (OUT)</strong>.</td></tr><tr><td>Employee taps <strong>Start Timer</strong> on a task</td><td>Creates a <strong>Timesheet</strong> row ONLY. <strong>Does not</strong> create a Checkin row.</td></tr><tr><td>Employee taps <strong>Stop Timer</strong></td><td>Closes the Timesheet row with <code>to_time</code> + hours. No Checkin row.</td></tr></tbody></table><p><strong>Payroll flow:</strong> Employee Checkin rows feed HRMS Auto Attendance → Attendance status → Salary Slip <code>payment_days</code>. Timesheets are for reporting / billable hours only.</p><h2 id="mode-2-—-timer-based" tabindex="-1">Mode 2 — Timer Based <a class="header-anchor" href="#mode-2-—-timer-based" aria-label="Permalink to &quot;Mode 2 — Timer Based&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">When to pick this</p><p>You want every attendance event tied to a specific task. The employee can&#39;t check in without declaring what they&#39;re going to work on.</p></div><table tabindex="0"><thead><tr><th>Action</th><th>What happens</th></tr></thead><tbody><tr><td>Employee taps <strong>Check In</strong></td><td>App asks <strong>&quot;pick a task&quot;</strong> first. On confirm, GPS is captured, the server creates <strong>Employee Checkin (IN)</strong> + opens a <strong>Timesheet</strong> row for that task.</td></tr><tr><td>Employee taps <strong>Check Out</strong></td><td>The running timer is automatically stopped. Server creates <strong>Employee Checkin (OUT)</strong> + closes the Timesheet row with hours.</td></tr><tr><td>Employee taps <strong>Start Timer</strong> on a task (Tasks tab)</td><td>Same effect as Check In + picking that task.</td></tr><tr><td>Employee taps <strong>Stop Timer</strong> (Tasks tab)</td><td>Same effect as Check Out.</td></tr></tbody></table><p><strong>The Check-In button and the Tasks tab share one live timer.</strong> Starting from either place shows the running state in both. Switching task mid-day is supported: the employee stops the current task (writes OUT + closes row) and starts another (writes new IN + opens new row) — creating <strong>two</strong> attendance pairs for the day.</p><p><strong>Prerequisite:</strong> Every employee needs at least one open <strong>Task</strong> assigned to them (status = Open / Working, <code>_assign</code> contains their user). If they have no open tasks the Check-In screen shows &quot;No tasks assigned&quot; instead of letting them tap through.</p><h2 id="why-a-toggle-and-not-both-at-once" tabindex="-1">Why a toggle, and not both at once? <a class="header-anchor" href="#why-a-toggle-and-not-both-at-once" aria-label="Permalink to &quot;Why a toggle, and not both at once?&quot;">​</a></h2><p>Earlier versions of Fateh HR ran BOTH flows: the big button wrote a Checkin, AND the timer also wrote one. If an employee used the button AND started a task timer, attendance was double-counted, Auto Attendance produced odd hours, and <code>payment_days</code> on the salary slip was off.</p><p>One mode = one source of truth for attendance. Pick the one that matches your operations.</p><h2 id="daily-hours-card-on-the-home-screen" tabindex="-1">Daily hours card on the home screen <a class="header-anchor" href="#daily-hours-card-on-the-home-screen" aria-label="Permalink to &quot;Daily hours card on the home screen&quot;">​</a></h2><p>Regardless of mode, the app home screen shows a <strong>&quot;Worked today&quot;</strong> card with the sum of completed IN → OUT pairs for the current site-local day. When an IN is open (no matching OUT yet) the card <strong>ticks live</strong> with a small green pulse — employees can see the running number tick up second-by-second.</p><figure class="screenshot"><img src="'+t+'" alt="Home screen"><figcaption>The Worked today card appears just below the big Check-in card on the home screen (1.0.22+).</figcaption></figure><h2 id="switching-modes-mid-month" tabindex="-1">Switching modes mid-month <a class="header-anchor" href="#switching-modes-mid-month" aria-label="Permalink to &quot;Switching modes mid-month&quot;">​</a></h2><p>Perfectly safe. The mode only affects <strong>new</strong> rows written after the switch. Historical Employee Checkin rows and Timesheets stay as-is. Auto Attendance keeps processing whichever rows exist.</p><p>If you flip from Timer Based → Checkin Based mid-day while an employee has a timer running, the next time they open the app they&#39;ll see their running timer on the Tasks tab and can stop it normally.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/guide/check-in">Check-in &amp; Check-out</a> — the big button flow</li><li><a href="/guide/tasks">Tasks</a> — the timer flow</li></ul>',27)])])}const k=o(r,[["render",i]]);export{u as __pageData,k as default};
